import{c as t,a7 as e,y as a,B as n}from"./chunks/framework.3cjvm90C.js";const c=JSON.parse('{"title":"MindSpeed 长序列训练：算法演进与实战指南","description":"介绍 MindSpeed 平台上长序列训练的三种上下文并行算法（Ulysses、RingAttention、Hybrid）及调优实践","frontmatter":{"title":"MindSpeed 长序列训练：算法演进与实战指南","description":"介绍 MindSpeed 平台上长序列训练的三种上下文并行算法（Ulysses、RingAttention、Hybrid）及调优实践"},"headers":[],"relativePath":"ascend/long_context_length.md","filePath":"ascend/long_context_length.md","lastUpdated":1782456021000}'),i={name:"ascend/long_context_length.md"};function r(l,s,d,o,h,g){return e(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="mindspeed-长序列训练-算法演进与实战指南" tabindex="-1">MindSpeed 长序列训练：算法演进与实战指南 <a class="header-anchor" href="#mindspeed-长序列训练-算法演进与实战指南" aria-label="Permalink to “MindSpeed 长序列训练：算法演进与实战指南”">​</a></h1><h2 id="_1-概述-从-8k-研发到-64k-的演进策略" tabindex="-1">1. 概述：从 8K 研发到 64K 的演进策略 <a class="header-anchor" href="#_1-概述-从-8k-研发到-64k-的演进策略" aria-label="Permalink to “1. 概述：从 8K 研发到 64K 的演进策略”">​</a></h2><p>在进行长序列（Context Length &gt; 32K）优化前，必须确保 <strong>短序列（如 8K）基础性能</strong> 已达标。</p><h3 id="核心调优原则" tabindex="-1">核心调优原则 <a class="header-anchor" href="#核心调优原则" aria-label="Permalink to “核心调优原则”">​</a></h3><ul><li><strong>显存优先</strong>：利用融合算子（<code>use-fused-swiglu</code>、<code>use-fused-rmsnorm</code>）和分布式优化器（<code>use-distributed-optimizer</code>）压低基础显存。</li><li><strong>通信掩盖</strong>：开启 <code>overlap-grad-reduce</code> 实现梯度同步与计算的重叠。</li><li><strong>策略选择</strong>：在 GQA（Grouped Query Attention）场景下，优先使用 <strong>流水并行 (PP)</strong> 或 <strong>上下文并行 (CP)</strong> 代替张量并行 (TP)，以避免由于 Head 数限制导致的算力利用率下降。</li></ul><h2 id="_2-三大上下文并行-cp-算法对比" tabindex="-1">2. 三大上下文并行 (CP) 算法对比 <a class="header-anchor" href="#_2-三大上下文并行-cp-算法对比" aria-label="Permalink to “2. 三大上下文并行 (CP) 算法对比”">​</a></h2><p>为了突破单卡 KV Cache 的显存瓶颈，MindSpeed 提供了三种主流的上下文并行算法：</p><table tabindex="0"><thead><tr><th><strong>算法方案</strong></th><th><strong>切分维度</strong></th><th><strong>通信模式</strong></th><th><strong>核心优势</strong></th><th><strong>适用场景</strong></th></tr></thead><tbody><tr><td><strong>Ulysses</strong></td><td>注意力头 (Head/Dim)</td><td>All-to-All</td><td>通信效率高，计算密集度高</td><td>满足 <code>heads % CP == 0</code> 的标准模型</td></tr><tr><td><strong>RingAttention</strong></td><td>序列长度 (Sequence)</td><td>Ring P2P (SendRecv)</td><td>显存优化极佳，逻辑简单</td><td>超长序列（64K+）、高带宽环境</td></tr><tr><td><strong>Hybrid (CP)</strong></td><td>混合维度 (S + Dim)</td><td>All-to-All + Ring</td><td>兼顾二者，突破 Head 数限制</td><td><strong>GQA 模型、跨节点大规模集群</strong></td></tr></tbody></table><h2 id="_3-ulysses-基于注意力头切分的方案" tabindex="-1">3. Ulysses：基于注意力头切分的方案 <a class="header-anchor" href="#_3-ulysses-基于注意力头切分的方案" aria-label="Permalink to “3. Ulysses：基于注意力头切分的方案”">​</a></h2><p><strong>Ulysses</strong> 是长序列训练的首选方案，尤其在高性能网络（如昇腾 HCCS）中表现优异。</p><h3 id="_3-1-核心逻辑" tabindex="-1">3.1 核心逻辑 <a class="header-anchor" href="#_3-1-核心逻辑" aria-label="Permalink to “3.1 核心逻辑”">​</a></h3><p>通过两次 <strong>All-to-All</strong> 转置，将数据在“序列维度切分”与“注意力头维度切分”之间转换。</p><ol><li><strong>输入</strong>：各卡持有序列的 $1/P$。</li><li><strong>通信 1</strong>：All-to-All 转置，使得每张卡持有全量序列，但仅持有部分的 Head。</li><li><strong>计算</strong>：在本地独立完成该 Head 的 Attention 计算。</li><li><strong>通信 2</strong>：All-to-All 还原回序列切分状态。</li></ol><h3 id="_3-2-开启方式与约束" tabindex="-1">3.2 开启方式与约束 <a class="header-anchor" href="#_3-2-开启方式与约束" aria-label="Permalink to “3.2 开启方式与约束”">​</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--context-parallel-algo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ulysses_cp_algo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--context-parallel-size </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--group-query-attention </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--num-query-groups </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 必须满足 num_query_groups &gt;= cp_size</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_4-ringattention-环形序列并行" tabindex="-1">4. RingAttention：环形序列并行 <a class="header-anchor" href="#_4-ringattention-环形序列并行" aria-label="Permalink to “4. RingAttention：环形序列并行”">​</a></h2><p><strong>RingAttention</strong> 采用分块计算（Blockwise）的思想。</p><h3 id="_4-1-性能关键-通算掩盖" tabindex="-1">4.1 性能关键：通算掩盖 <a class="header-anchor" href="#_4-1-性能关键-通算掩盖" aria-label="Permalink to “4.1 性能关键：通算掩盖”">​</a></h3><p>为了让计算掩盖通信延迟，每个分块（Block）的序列长度 $c$ 必须满足： $$ c \\geq \\frac{F \\text{ (设备算力)} }{B \\text{ (通信带宽)} } $$</p><ul><li><strong>优化路径</strong>：RSA (早期) $\\rightarrow$ BPT (分块) $\\rightarrow$ <strong>MindSpeed RingAttention (并行环形 P2P)</strong>。</li><li><strong>开启方式</strong>：<code>--context-parallel-algo megatron_cp_algo</code>。</li></ul><h2 id="_5-hybrid-cp-mindspeed-的最佳实践" tabindex="-1">5. Hybrid CP：MindSpeed 的最佳实践 <a class="header-anchor" href="#_5-hybrid-cp-mindspeed-的最佳实践" aria-label="Permalink to “5. Hybrid CP：MindSpeed 的最佳实践”">​</a></h2><p><strong>Hybrid</strong> 方案是目前处理超长序列（如 64K/128K）且兼顾多节点扩展的最优解。</p><h3 id="_5-1-混合架构逻辑" tabindex="-1">5.1 混合架构逻辑 <a class="header-anchor" href="#_5-1-混合架构逻辑" aria-label="Permalink to “5.1 混合架构逻辑”">​</a></h3><p>它将 CP 维度细分为 <strong>Ulysses 子组</strong> 和 <strong>Ring 子组</strong>：</p><ul><li><strong>节点内 (Intra-node)</strong>：使用 Ulysses 运行 All-to-All，利用高速内部带宽处理维度转置。</li><li><strong>节点间 (Inter-node)</strong>：使用 RingAttention 运行 P2P 通信，降低跨机带宽压力。</li></ul><h3 id="_5-2-最佳实践配置" tabindex="-1">5.2 最佳实践配置 <a class="header-anchor" href="#_5-2-最佳实践配置" aria-label="Permalink to “5.2 最佳实践配置”">​</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--context-parallel-size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--context-parallel-algo </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">hybrid_cp_algo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--ulysses-degree-in-cp </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 总CP为8，其中Ulysses占2，Ring占4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><blockquote><p><strong>补充说明</strong>：确保 <code>TP * ulysses_size &lt;= 8</code>（单机卡数），将 All-to-All 限制在节点内，跨节点仅走 P2P 通信，此时系统效率最高。</p></blockquote><h2 id="_6-实战案例-chatglm3-6b-32k-64k-调优" tabindex="-1">6. 实战案例：ChatGLM3-6B 32K/64K 调优 <a class="header-anchor" href="#_6-实战案例-chatglm3-6b-32k-64k-调优" aria-label="Permalink to “6. 实战案例：ChatGLM3-6B 32K/64K 调优”">​</a></h2><p>在 ChatGLM3 的长序列预训练中，NPU A2 配合 MindSpeed 展现了卓越性能。</p><h3 id="性能表现对比" tabindex="-1">性能表现对比 <a class="header-anchor" href="#性能表现对比" aria-label="Permalink to “性能表现对比”">​</a></h3><table tabindex="0"><thead><tr><th><strong>硬件环境</strong></th><th><strong>序列长度</strong></th><th><strong>并行策略</strong></th><th><strong>吞吐量 (Token/s/p)</strong></th></tr></thead><tbody><tr><td>GPU A100</td><td>32K</td><td>Megatron-LM</td><td>2887.84</td></tr><tr><td><strong>NPU A2</strong></td><td><strong>32K</strong></td><td><strong>MindSpeed (Ulysses)</strong></td><td><strong>3006.24</strong> (↑ 4%)</td></tr></tbody></table><h3 id="核心优化路径总结" tabindex="-1">核心优化路径总结 <a class="header-anchor" href="#核心优化路径总结" aria-label="Permalink to “核心优化路径总结”">​</a></h3><ol><li><strong>关闭 TP/PP</strong>：针对 GQA=2 的模型，TP 容易导致算力浪费，优先切分序列维度。</li><li><strong>使能 CP=8</strong>：使用 Ulysses 解决 KV Cache 爆炸。</li><li><strong>融合算子全开</strong>：<code>use-fused-swiglu</code> 和 <code>use-fused-rmsnorm</code> 是长序列不 OOM 的基础。</li><li><strong>通信重叠</strong>：开启 <code>overlap-grad-reduce</code> 隐藏反向传播的通信开销。</li></ol>`,34)])])}const k=t(i,[["render",r]]);export{c as __pageData,k as default};
